import {
  Injectable, UnauthorizedException
}
from '@nestjs/common';
import {
  PassportStrategy
}
from '@nestjs/passport';
import {
  ExtractJwt, Strategy
}
from 'passport-jwt';
import {
  UsersRepository
}
from './users.repository';
import {
  InjectRepository
}
from '@nestjs/typeorm';
import {
  JwtPayload
}
from './jwt-payload.intreface';
import {
  Users
}
from './user.entity';
@Injectable()
export class JWTStrategy extends PassportStrategy(Strategy) {
  constructor(@InjectRepository(UsersRepository) private userRepository: UsersRepository,) {
    super({
      secretOrKey: 'topSecret51', jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
    });
  }
  async validate(payload: JwtPayload): Promise<Users> {
    const {
      username
    }
    = payload;
    const user: Users = await this.userRepository.findOne({
      where: {
        username
      },
    });
    if (!user) {
      throw new UnauthorizedException();
    }
    return user;
  }
}

